package com.example.petshop.data.dao

import androidx.room.*
import com.example.petshop.data.entity.Appointment
import com.example.petshop.data.entity.AppointmentStatus
import com.example.petshop.data.relation.AppointmentWithDetails
import kotlinx.coroutines.flow.Flow

@Dao
interface AppointmentDao {

    @Insert(onConflict = OnConflictStrategy.ABORT)
    suspend fun insert(appointment: Appointment): Long

    @Update
    suspend fun update(appointment: Appointment)

    @Delete
    suspend fun delete(appointment: Appointment)

    @Query("SELECT * FROM appointments WHERE appointmentId = :id")
    suspend fun getById(id: Int): Appointment?

    @Query("SELECT * FROM appointments ORDER BY scheduledAt DESC")
    fun getAllAppointments(): Flow<List<Appointment>>

    @Query("SELECT * FROM appointments WHERE clientId = :clientId ORDER BY scheduledAt DESC")
    fun getAppointmentsByClient(clientId: Int): Flow<List<Appointment>>

    @Query("SELECT * FROM appointments WHERE petId = :petId ORDER BY scheduledAt DESC")
    fun getAppointmentsByPet(petId: Int): Flow<List<Appointment>>

    @Query("SELECT * FROM appointments WHERE staffId = :staffId ORDER BY scheduledAt DESC")
    fun getAppointmentsByStaff(staffId: Int): Flow<List<Appointment>>

    @Query("SELECT * FROM appointments WHERE status = :status ORDER BY scheduledAt ASC")
    fun getAppointmentsByStatus(status: AppointmentStatus): Flow<List<Appointment>>

    @Query("""
        SELECT * FROM appointments
        WHERE scheduledAt >= :startOfDay AND scheduledAt <= :endOfDay
        ORDER BY scheduledAt ASC
    """)
    fun getAppointmentsForDay(startOfDay: Long, endOfDay: Long): Flow<List<Appointment>>

    @Query("""
        SELECT * FROM appointments
        WHERE scheduledAt >= :from AND scheduledAt <= :to
        ORDER BY scheduledAt ASC
    """)
    fun getAppointmentsInRange(from: Long, to: Long): Flow<List<Appointment>>

    @Query("UPDATE appointments SET status = :status, updatedAt = :updatedAt WHERE appointmentId = :id")
    suspend fun updateStatus(id: Int, status: AppointmentStatus, updatedAt: Long = System.currentTimeMillis())

    @Query("SELECT COUNT(*) FROM appointments WHERE status = :status")
    suspend fun countByStatus(status: AppointmentStatus): Int

    @Query(
        """
        SELECT COUNT(*) FROM appointments
        WHERE petId = :petId
          AND scheduledAt = :scheduledAt
          AND status IN ('PENDING','CONFIRMED','IN_PROGRESS')
        """
    )
    suspend fun countPetConflicts(petId: Int, scheduledAt: Long): Int

    @Query(
        """
        SELECT COUNT(*) FROM appointments
        WHERE timeSlotId = :timeSlotId
          AND status IN ('PENDING','CONFIRMED','IN_PROGRESS')
        """
    )
    suspend fun countActiveByTimeSlot(timeSlotId: Int): Int

    @Query("""
        SELECT * FROM appointments
        WHERE status IN ('PENDING','CONFIRMED','IN_PROGRESS')
        ORDER BY scheduledAt ASC
    """)
    fun getUpcomingAppointments(): Flow<List<Appointment>>

    @Transaction
    @Query("SELECT * FROM appointments ORDER BY scheduledAt DESC")
    fun getAllWithDetails(): Flow<List<AppointmentWithDetails>>

    @Transaction
    @Query("SELECT * FROM appointments WHERE clientId = :clientId ORDER BY scheduledAt DESC")
    fun getWithDetailsByClient(clientId: Int): Flow<List<AppointmentWithDetails>>

    @Query(
        """
        SELECT COUNT(*) FROM appointments
        WHERE scheduledAt = :scheduledAt
          AND status IN ('PENDING','CONFIRMED','IN_PROGRESS')
          AND (
               petId = :petId
               OR (:staffId IS NOT NULL AND staffId = :staffId)
          )
        """
    )
    suspend fun countConflicts(scheduledAt: Long, petId: Int, staffId: Int?): Int
}

package com.example.petshop.data.dao

import androidx.room.*
import com.example.petshop.data.entity.Appointment
import com.example.petshop.data.entity.AppointmentStatus
import com.example.petshop.data.relation.AppointmentWithDetails
import kotlinx.coroutines.flow.Flow

@Dao
interface AppointmentDao {

    @Insert(onConflict = OnConflictStrategy.ABORT)
    suspend fun insert(appointment: Appointment): Long

    @Update
    suspend fun update(appointment: Appointment)

    @Delete
    suspend fun delete(appointment: Appointment)

    @Query("SELECT * FROM appointments WHERE appointmentId = :id")
    suspend fun getById(id: Int): Appointment?

    @Query("SELECT * FROM appointments ORDER BY scheduledAt DESC")
    fun getAllAppointments(): Flow<List<Appointment>>

    @Query("SELECT * FROM appointments WHERE clientId = :clientId ORDER BY scheduledAt DESC")
    fun getAppointmentsByClient(clientId: Int): Flow<List<Appointment>>

    @Query("SELECT * FROM appointments WHERE petId = :petId ORDER BY scheduledAt DESC")
    fun getAppointmentsByPet(petId: Int): Flow<List<Appointment>>

    @Query("SELECT * FROM appointments WHERE staffId = :staffId ORDER BY scheduledAt DESC")
    fun getAppointmentsByStaff(staffId: Int): Flow<List<Appointment>>

    @Query("SELECT * FROM appointments WHERE status = :status ORDER BY scheduledAt ASC")
    fun getAppointmentsByStatus(status: AppointmentStatus): Flow<List<Appointment>>

    @Query("""
        SELECT * FROM appointments
        WHERE scheduledAt >= :startOfDay AND scheduledAt <= :endOfDay
        ORDER BY scheduledAt ASC
    """)
    fun getAppointmentsForDay(startOfDay: Long, endOfDay: Long): Flow<List<Appointment>>

    @Query("""
        SELECT * FROM appointments
        WHERE scheduledAt >= :from AND scheduledAt <= :to
        ORDER BY scheduledAt ASC
    """)
    fun getAppointmentsInRange(from: Long, to: Long): Flow<List<Appointment>>

    @Query("UPDATE appointments SET status = :status, updatedAt = :updatedAt WHERE appointmentId = :id")
    suspend fun updateStatus(id: Int, status: AppointmentStatus, updatedAt: Long = System.currentTimeMillis())

    @Query("SELECT COUNT(*) FROM appointments WHERE status = :status")
    suspend fun countByStatus(status: AppointmentStatus): Int

    @Query(
        """
        SELECT COUNT(*) FROM appointments
        WHERE petId = :petId
          AND scheduledAt = :scheduledAt
          AND status IN ('PENDING','CONFIRMED','IN_PROGRESS')
        """
    )
    suspend fun countPetConflicts(petId: Int, scheduledAt: Long): Int

    @Query(
        """
        SELECT COUNT(*) FROM appointments
        WHERE timeSlotId = :timeSlotId
          AND status IN ('PENDING','CONFIRMED','IN_PROGRESS')
        """
    )
    suspend fun countActiveByTimeSlot(timeSlotId: Int): Int

    @Query(
        """
        SELECT COUNT(*) FROM appointments
        WHERE staffId = :staffId
          AND scheduledAt = :scheduledAt
          AND appointmentId != :excludeAppointmentId
          AND status IN ('PENDING','CONFIRMED','IN_PROGRESS')
        """
    )
    suspend fun countStaffConflictsAtTime(
        staffId: Int,
        scheduledAt: Long,
        excludeAppointmentId: Int
    ): Int

    @Query("""
        SELECT * FROM appointments
        WHERE status IN ('PENDING','CONFIRMED','IN_PROGRESS')
        ORDER BY scheduledAt ASC
    """)
    fun getUpcomingAppointments(): Flow<List<Appointment>>

    @Transaction
    @Query("SELECT * FROM appointments ORDER BY scheduledAt DESC")
    fun getAllWithDetails(): Flow<List<AppointmentWithDetails>>

    @Transaction
    @Query("SELECT * FROM appointments WHERE clientId = :clientId ORDER BY scheduledAt DESC")
    fun getWithDetailsByClient(clientId: Int): Flow<List<AppointmentWithDetails>>

    @Query(
        """
        SELECT COUNT(*) FROM appointments
        WHERE scheduledAt = :scheduledAt
          AND status IN ('PENDING','CONFIRMED','IN_PROGRESS')
          AND (
               petId = :petId
               OR (:staffId IS NOT NULL AND staffId = :staffId)
          )
        """
    )
    suspend fun countConflicts(scheduledAt: Long, petId: Int, staffId: Int?): Int
}

package com.example.petshop.data.dao
import androidx.room.* import com.example.petshop.data.entity.VetTimeSlot import kotlinx.coroutines.flow.Flow
@Dao interface VetTimeSlotDao {
@Insert(onConflict = OnConflictStrategy.ABORT) suspend fun insert(slot: VetTimeSlot): Long
@Update suspend fun update(slot: VetTimeSlot)
@Delete suspend fun delete(slot: VetTimeSlot)
@Query("SELECT * FROM vet_time_slots WHERE slotId = :id") suspend fun getById(id: Int): VetTimeSlot?
@Query("SELECT * FROM vet_time_slots WHERE staffId = :staffId ORDER BY slotStartTime ASC") fun getSlotsByStaff(staffId: Int): Flow<List<VetTimeSlot>>
@Query(""" SELECT * FROM vet_time_slots WHERE staffId = :staffId AND slotStartTime >= :from AND slotStartTime <= :to ORDER BY slotStartTime ASC """) fun getSlotsByStaffInRange(staffId: Int, from: Long, to: Long): Flow<List<VetTimeSlot>>
@Query(""" SELECT * FROM vet_time_slots WHERE staffId = :staffId AND isBooked = false AND slotStartTime >= :from AND slotStartTime <= :to ORDER BY slotStartTime ASC """) fun getAvailableSlotsByStaffInRange(staffId: Int, from: Long, to: Long): Flow<List<VetTimeSlot>>
@Query(""" SELECT COUNT(*) FROM vet_time_slots WHERE staffId = :staffId AND isBooked = true AND slotStartTime = :slotStartTime """) suspend fun isSlotBooked(staffId: Int, slotStartTime: Long): Int
@Query("UPDATE vet_time_slots SET isBooked = :isBooked, appointmentId = :appointmentId WHERE slotId = :slotId") suspend fun updateBookingStatus(slotId: Int, isBooked: Boolean, appointmentId: Int?)
@Query("SELECT * FROM vet_time_slots WHERE appointmentId = :appointmentId") suspend fun getSlotByAppointmentId(appointmentId: Int): VetTimeSlot?
@Query("DELETE FROM vet_time_slots WHERE slotStartTime < :beforeTime") suspend fun deleteOldSlots(beforeTime: Long) }

package com.example.petshop.data.dao

import androidx.room.*
import com.example.petshop.data.entity.VetTimeSlot
import kotlinx.coroutines.flow.Flow

@Dao
interface VetTimeSlotDao {

    @Insert(onConflict = OnConflictStrategy.ABORT)
    suspend fun insert(slot: VetTimeSlot): Long

    @Update
    suspend fun update(slot: VetTimeSlot)

    @Delete
    suspend fun delete(slot: VetTimeSlot)

    @Query("SELECT * FROM vet_time_slots WHERE slotId = :id")
    suspend fun getById(id: Int): VetTimeSlot?

    @Query("SELECT * FROM vet_time_slots WHERE staffId = :staffId ORDER BY slotStartTime ASC")
    fun getSlotsByStaff(staffId: Int): Flow<List<VetTimeSlot>>

    @Query("""
        SELECT * FROM vet_time_slots 
        WHERE staffId = :staffId 
        AND slotStartTime >= :from 
        AND slotStartTime <= :to 
        ORDER BY slotStartTime ASC
    """)
    fun getSlotsByStaffInRange(staffId: Int, from: Long, to: Long): Flow<List<VetTimeSlot>>

    @Query("""
        SELECT * FROM vet_time_slots 
        WHERE staffId = :staffId 
        AND isBooked = false 
        AND slotStartTime >= :from 
        AND slotStartTime <= :to 
        ORDER BY slotStartTime ASC
    """)
    fun getAvailableSlotsByStaffInRange(staffId: Int, from: Long, to: Long): Flow<List<VetTimeSlot>>

    @Query("""
        SELECT COUNT(*) FROM vet_time_slots 
        WHERE staffId = :staffId 
        AND isBooked = true 
        AND slotStartTime = :slotStartTime
    """)
    suspend fun isSlotBooked(staffId: Int, slotStartTime: Long): Int

    @Query("UPDATE vet_time_slots SET isBooked = :isBooked, appointmentId = :appointmentId WHERE slotId = :slotId")
    suspend fun updateBookingStatus(slotId: Int, isBooked: Boolean, appointmentId: Int?)

    @Query("SELECT * FROM vet_time_slots WHERE appointmentId = :appointmentId")
    suspend fun getSlotByAppointmentId(appointmentId: Int): VetTimeSlot?

    @Query("SELECT * FROM vet_time_slots WHERE staffId = :staffId AND slotStartTime = :slotStartTime LIMIT 1")
    suspend fun getByStaffAndStartTime(staffId: Int, slotStartTime: Long): VetTimeSlot?

    @Query("DELETE FROM vet_time_slots WHERE slotStartTime < :beforeTime")
    suspend fun deleteOldSlots(beforeTime: Long)
}

package com.example.petshop.ui.screens

import android.app.DatePickerDialog
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.LazyRow
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import androidx.lifecycle.viewmodel.compose.viewModel
import com.example.petshop.data.entity.*
import com.example.petshop.data.relation.AppointmentWithDetails
import com.example.petshop.ui.components.IosTimeSlider
import com.example.petshop.ui.navigation.SessionManager
import com.example.petshop.ui.theme.*
import com.example.petshop.ui.viewmodel.AppointmentViewModel
import java.text.SimpleDateFormat
import java.util.*

private fun formatDt(millis: Long): String =
    SimpleDateFormat("MMM dd, yyyy  hh:mm a", Locale.getDefault()).format(Date(millis))

private fun statusColor(status: AppointmentStatus): Color = when (status) {
    AppointmentStatus.PENDING     -> StatusPending
    AppointmentStatus.CONFIRMED   -> StatusConfirmed
    AppointmentStatus.IN_PROGRESS -> StatusInProgress
    AppointmentStatus.COMPLETED   -> StatusCompleted
    AppointmentStatus.CANCELLED   -> StatusCancelled
    AppointmentStatus.NO_SHOW     -> StatusNoShow
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun AppointmentsScreen(
    onBack: () -> Unit,
    vm: AppointmentViewModel = viewModel()
) {
    val appointments by vm.appointments.collectAsState()
    val clients by vm.clients.collectAsState()
    val staffList by vm.staffList.collectAsState()
    val services by vm.services.collectAsState()
    val petsForClient by vm.petsForClient.collectAsState()
    val addError by vm.addError.collectAsState()
    val currentUser = SessionManager.currentUser
    val isStaffView = currentUser?.role == UserRole.ADMIN || currentUser?.role == UserRole.STAFF

    var showAdd by remember { mutableStateOf(false) }
    var filterStatus by remember { mutableStateOf<AppointmentStatus?>(null) }

    val filtered = if (filterStatus == null) appointments
    else appointments.filter { it.appointment.status == filterStatus }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Appointments", fontWeight = FontWeight.Bold) },
                navigationIcon = {
                    IconButton(onClick = onBack) { Icon(Icons.Filled.ArrowBack, "Back") }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = MaterialTheme.colorScheme.primary,
                    titleContentColor = MaterialTheme.colorScheme.onPrimary,
                    navigationIconContentColor = MaterialTheme.colorScheme.onPrimary
                )
            )
        },
        floatingActionButton = {
            if (isStaffView) {
                FloatingActionButton(onClick = { showAdd = true }) {
                    Icon(Icons.Filled.Add, "New Appointment")
                }
            }
        }
    ) { padding ->
        Column(modifier = Modifier.padding(padding)) {
            // Status filter chips
            LazyRow(
                contentPadding = PaddingValues(horizontal = 16.dp, vertical = 8.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                item {
                    FilterChip(
                        selected = filterStatus == null,
                        onClick  = { filterStatus = null },
                        label    = { Text("All") }
                    )
                }
                items(AppointmentStatus.values()) { status ->
                    FilterChip(
                        selected = filterStatus == status,
                        onClick  = { filterStatus = if (filterStatus == status) null else status },
                        label    = { Text(status.name) }
                    )
                }
            }

            if (filtered.isEmpty()) {
                Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                    Text("No appointments found", color = MaterialTheme.colorScheme.outline)
                }
            } else {
                LazyColumn(
                    contentPadding = PaddingValues(16.dp),
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    items(filtered, key = { it.appointment.appointmentId }) {
                        AppointmentCard(it, onStatusChange = { id, s -> vm.updateStatus(id, s) }, isStaffView)
                    }
                }
            }
        }
    }

    if (showAdd && isStaffView) {
        AddAppointmentDialog(
            clients = clients,
            petsForClient = petsForClient,
            staffList = staffList,
            services = services,
            externalError = addError,
            onClientSelected = vm::selectClient,
            onDismiss = {
                vm.clearAddError()
                showAdd = false
            },
            onConfirm = { clientId, petId, staffId, serviceId, scheduledAt, notes ->
                vm.addAppointment(clientId, petId, staffId, serviceId, scheduledAt, notes) { success ->
                    if (success) {
                        vm.clearAddError()
                        showAdd = false
                    }
                }
            }
        )
    }
}

@Composable
private fun AppointmentCard(
    item: AppointmentWithDetails,
    onStatusChange: (Int, AppointmentStatus) -> Unit,
    isStaffView: Boolean
) {
    var showStatusMenu by remember { mutableStateOf(false) }
    val apt = item.appointment

    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(12.dp),
        elevation = CardDefaults.cardElevation(2.dp)
    ) {
        Column(Modifier.padding(16.dp)) {
            Row(
                Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column(Modifier.weight(1f)) {
                    Text(
                        "${item.client?.firstName ?: "?"} ${item.client?.lastName ?: ""}",
                        fontWeight = FontWeight.SemiBold
                    )
                    Text(
                        "Pet: ${item.pet?.name ?: "?"} (${item.pet?.species ?: ""})",
                        style = MaterialTheme.typography.bodySmall
                    )
                }
                if (isStaffView) {
                    Box {
                        SuggestionChip(
                            onClick = { showStatusMenu = true },
                            label   = { Text(apt.status.name, style = MaterialTheme.typography.labelSmall) },
                            colors  = SuggestionChipDefaults.suggestionChipColors(
                                containerColor = statusColor(apt.status).copy(alpha = 0.15f),
                                labelColor     = statusColor(apt.status)
                            )
                        )
                        DropdownMenu(expanded = showStatusMenu, onDismissRequest = { showStatusMenu = false }) {
                            AppointmentStatus.values().forEach { s ->
                                DropdownMenuItem(
                                    text    = { Text(s.name) },
                                    onClick = { onStatusChange(apt.appointmentId, s); showStatusMenu = false }
                                )
                            }
                        }
                    }
                } else {
                    SuggestionChip(
                        onClick = {},
                        enabled = false,
                        label   = { Text(apt.status.name, style = MaterialTheme.typography.labelSmall) },
                        colors  = SuggestionChipDefaults.suggestionChipColors(
                            containerColor = statusColor(apt.status).copy(alpha = 0.15f),
                            labelColor     = statusColor(apt.status)
                        )
                    )
                }
            }
            Spacer(Modifier.height(6.dp))
            Row(verticalAlignment = Alignment.CenterVertically) {
                Icon(Icons.Filled.AccessTime, null, Modifier.size(14.dp), tint = MaterialTheme.colorScheme.outline)
                Spacer(Modifier.width(4.dp))
                Text(formatDt(apt.scheduledAt), style = MaterialTheme.typography.bodySmall)
            }
            if (apt.notes.isNotBlank()) {
                Spacer(Modifier.height(4.dp))
                Text(" ${apt.notes}", style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.outline)
            }
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
private fun AddAppointmentDialog(
    clients: List<Client>,
    petsForClient: List<Pet>,
    staffList: List<Staff>,
    services: List<Service>,
    externalError: String?,
    onClientSelected: (Int) -> Unit,
    onDismiss: () -> Unit,
    onConfirm: (Int, Int, Int?, Int?, Long, String) -> Unit
) {
    val context  = LocalContext.current
    val calendar = remember { Calendar.getInstance() }

    var selectedClient  by remember { mutableStateOf<Client?>(null) }
    var selectedPet     by remember { mutableStateOf<Pet?>(null) }
    var selectedStaff   by remember { mutableStateOf<Staff?>(null) }
    var selectedService by remember { mutableStateOf<Service?>(null) }
    var scheduledAt     by remember { mutableLongStateOf(System.currentTimeMillis()) }
    var notes           by remember { mutableStateOf("") }
    var error           by remember { mutableStateOf("") }
    var showTimeSlider  by remember { mutableStateOf(false) }

    val hour = Calendar.getInstance().apply { timeInMillis = scheduledAt }.get(Calendar.HOUR_OF_DAY)
    val minute = Calendar.getInstance().apply { timeInMillis = scheduledAt }.get(Calendar.MINUTE)

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("New Appointment") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                // Client dropdown
                AppDropdown(
                    label    = "Client *",
                    selected = selectedClient?.let { "${it.firstName} ${it.lastName}" } ?: "",
                    options  = clients.map { "${it.firstName} ${it.lastName}" },
                    onSelect = { idx ->
                        selectedClient = clients[idx]
                        selectedPet = null
                        onClientSelected(clients[idx].clientId)
                    }
                )
                // Pet dropdown (filtered)
                AppDropdown(
                    label    = "Pet *",
                    selected = selectedPet?.name ?: "",
                    options  = petsForClient.map { it.name },
                    onSelect = { idx -> selectedPet = petsForClient[idx] }
                )
                // Staff dropdown (optional)
                AppDropdown(
                    label    = "Staff (optional)",
                    selected = selectedStaff?.let { "${it.firstName} ${it.lastName}" } ?: "None",
                    options  = listOf("None") + staffList.map { "${it.firstName} ${it.lastName}" },
                    onSelect = { idx -> selectedStaff = if (idx == 0) null else staffList[idx - 1] }
                )
                // Service dropdown (optional)
                AppDropdown(
                    label    = "Service (optional)",
                    selected = selectedService?.name ?: "None",
                    options  = listOf("None") + services.map { it.name },
                    onSelect = { idx -> selectedService = if (idx == 0) null else services[idx - 1] }
                )
                // Date/Time
                Text(
                    "  ${formatDt(scheduledAt)}",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.primary
                )
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    OutlinedButton(onClick = {
                        DatePickerDialog(
                            context,
                            { _, y, m, d -> calendar.set(y, m, d); scheduledAt = calendar.timeInMillis },
                            calendar.get(Calendar.YEAR),
                            calendar.get(Calendar.MONTH),
                            calendar.get(Calendar.DAY_OF_MONTH)
                        ).show()
                    }, modifier = Modifier.weight(1f)) { Text("Date") }

                    OutlinedButton(onClick = {
                        showTimeSlider = true
                    }, modifier = Modifier.weight(1f)) { Text("Time") }
                }
                OutlinedTextField(
                    value = notes, onValueChange = { notes = it },
                    label = { Text("Notes") }, maxLines = 3,
                    modifier = Modifier.fillMaxWidth()
                )
                if (error.isNotBlank())
                    Text(error, color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.bodySmall)
                if (!externalError.isNullOrBlank())
                    Text(externalError, color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.bodySmall)
            }
        },
        confirmButton = {
            Button(onClick = {
                if (selectedClient == null || selectedPet == null) { error = "Client and Pet are required"; return@Button }
                onConfirm(
                    selectedClient!!.clientId,
                    selectedPet!!.petId,
                    selectedStaff?.staffId,
                    selectedService?.serviceId,
                    scheduledAt, notes
                )
            }) { Text("Book") }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel") } }
    )

    if (showTimeSlider) {
        AlertDialog(
            onDismissRequest = { showTimeSlider = false },
            title = { Text("Select Time") },
            text = {
                IosTimeSlider(
                    hour = hour,
                    minute = minute,
                    onTimeChange = { h, m ->
                        calendar.set(Calendar.HOUR_OF_DAY, h)
                        calendar.set(Calendar.MINUTE, m)
                        scheduledAt = calendar.timeInMillis
                    }
                )
            },
            confirmButton = {
                Button(onClick = { showTimeSlider = false }) { Text("Done") }
            }
        )
    }
}

/** Reusable dropdown composable. */
@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun AppDropdown(label: String, selected: String, options: List<String>, onSelect: (Int) -> Unit) {
    var expanded by remember { mutableStateOf(false) }
    ExposedDropdownMenuBox(expanded = expanded, onExpandedChange = { expanded = it }) {
        OutlinedTextField(
            value = selected, onValueChange = {},
            readOnly = true, label = { Text(label) },
            trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded) },
            modifier = Modifier.fillMaxWidth().menuAnchor(MenuAnchorType.PrimaryNotEditable)
        )
        ExposedDropdownMenu(expanded = expanded, onDismissRequest = { expanded = false }) {
            options.forEachIndexed { i, opt ->
                DropdownMenuItem(text = { Text(opt) }, onClick = { onSelect(i); expanded = false })
            }
        }
    }
}

